1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	const itemBasePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
16	
17	const quotePremium = (items: Item[]): number => {
18	  const basePremium = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
19	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
20	  return Math.ceil(basePremium + firstInsurance) + PROCESSING_FEE;
21	};
22	
23	export const runScenario = (scenario: Scenario): unknown => {
24	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
25	  return { results };
26	};
